rollback_steps:
## 回滚步骤
```
kubectl rollout undo deployment/${deployment} -n ${namespace}
kubectl rollout status deployment/${deployment} -n ${namespace}
```
如修改了 JAVA_OPTS 环境变量，回滚会自动恢复上一版本配置。

steps:
## 1. 定位错误来源
```
tail -f /var/log/nginx/error.log | grep -i upstream
# 看具体错误：connect refused / timeout / reset by peer
awk '/upstream/{print $NF}' /var/log/nginx/error.log | sort | uniq -c | sort -rn | head
```

## 2. 检查后端健康
```
# 列出 upstream 配置
nginx -T 2>/dev/null | grep -A10 "upstream ${upstream_name}"
# 直连后端探活
for backend in ${backend_list}; do
  curl -fsS -o /dev/null -w "$backend: %{http_code} time=%{time_total}\n" -m 3 http://$backend/health
done
# 看后端实例资源
kubectl top pod -n ${namespace} -l app=${backend_app}
```

## 3. 摘除异常实例
```
# 临时方案：在 upstream 中标记 down
sed -i 's|server ${bad_backend};|server ${bad_backend} down;|' /etc/nginx/conf.d/${app}.conf
nginx -t && nginx -s reload
```

## 4. 调优 keepalive 与超时
```
# 编辑 /etc/nginx/conf.d/${app}.conf
# upstream ${upstream_name} {
#   server backend1:8080 max_fails=3 fail_timeout=30s;
#   keepalive 256;
#   keepalive_requests 10000;
#   keepalive_timeout 60s;
# }
# location / {
#   proxy_pass http://${upstream_name};
#   proxy_http_version 1.1;
#   proxy_set_header Connection "";
#   proxy_connect_timeout 5s;
#   proxy_send_timeout 30s;
#   proxy_read_timeout 30s;
#   proxy_next_upstream error timeout http_502 http_503;
# }
nginx -t && nginx -s reload
```

## 5. 后端扩容（如确为容量不足）
```
kubectl scale deployment ${backend_app} -n ${namespace} --replicas=${new_replicas}
kubectl rollout status deployment ${backend_app} -n ${namespace}
```

## 6. 验证恢复
```
# 5xx 比例
curl -sG 'http://prometheus:9090/api/v1/query' --data-urlencode 'query=sum(rate(nginx_http_response_codes{code=~"5.."}[5m])) / sum(rate(nginx_http_response_codes[5m]))'
# upstream 响应时间
curl -sG 'http://prometheus:9090/api/v1/query' --data-urlencode 'query=histogram_quantile(0.99, rate(nginx_upstream_response_time_bucket[5m]))'
# 端到端测试
for i in {1..50}; do curl -sw '%{http_code}\n' -o /dev/null https://${domain}/api/health; done | sort | uniq -c
```
